// Advanced filtering middleware
function filterPosts(req, res, next) {
  let filteredPosts = [...posts];

  // Filter by date range
  if (req.query.startDate) {
    const startDate = new Date(req.query.startDate);
    filteredPosts = filteredPosts.filter(p => p.createdAt >= startDate);
  }
  if (req.query.endDate) {
    const endDate = new Date(req.query.endDate);
    filteredPosts = filteredPosts.filter(p => p.createdAt <= endDate);
  }

  // Search in title
  if (req.query.search) {
    const searchTerm = req.query.search.toLowerCase();
    filteredPosts = filteredPosts.filter(p => 
      p.title.toLowerCase().includes(searchTerm)
    );
  }

  // Filter by author name
  if (req.query.authorName) {
    const authorName = req.query.authorName.toLowerCase();
    filteredPosts = filteredPosts.filter(p => 
      p.authorName.toLowerCase().includes(authorName)
    );
  }

  // Filter by content length
  if (req.query.minLength) {
    filteredPosts = filteredPosts.filter(p => 
      p.content.length >= parseInt(req.query.minLength)
    );
  }

  req.filteredPosts = filteredPosts;
  next();
}

// Sorting middleware
function sortPosts(req, res, next) {
  const sortBy = req.query.sortBy || 'createdAt';
  const order = req.query.order === 'asc' ? 1 : -1;

  const validSortFields = ['createdAt', 'updatedAt', 'title', 'content'];
  if (!validSortFields.includes(sortBy)) {
    return res.status(400).json({ 
      error: `Invalid sort field. Must be one of: ${validSortFields.join(', ')}` 
    });
  }

  req.filteredPosts.sort((a, b) => {
    if (sortBy === 'title' || sortBy === 'content') {
      return order * a[sortBy].localeCompare(b[sortBy]);
    }
    return order * (new Date(a[sortBy]) - new Date(b[sortBy]));
  });

  next();
}

// Field selection middleware
function selectFields(req, res, next) {
  const fields = req.query.fields ? req.query.fields.split(',') : null;

  if (fields) {
    req.selectedPosts = req.filteredPosts.map(post => {
      const selected = {};
      fields.forEach(field => {
        if (post.hasOwnProperty(field)) {
          selected[field] = post[field];
        }
      });
      return selected;
    });
  } else {
    req.selectedPosts = req.filteredPosts;
  }

  next();
}

// Enhanced GET /api/posts with all middleware
app.get('/api/posts', filterPosts, sortPosts, selectFields, (req, res) => {
  const page = parseInt(req.query.page) || 1;
  const limit = parseInt(req.query.limit) || 10;
  const startIndex = (page - 1) * limit;
  const endIndex = page * limit;

  const paginatedPosts = req.selectedPosts.slice(startIndex, endIndex);

  const response = {
    data: paginatedPosts,
    pagination: {
      total: req.selectedPosts.length,
      page,
      limit,
      pages: Math.ceil(req.selectedPosts.length / limit)
    },
    filters: {
      startDate: req.query.startDate || null,
      endDate: req.query.endDate || null,
      search: req.query.search || null,
      authorName: req.query.authorName || null,
      minLength: req.query.minLength || null
    },
    sort: {
      by: req.query.sortBy || 'createdAt',
      order: req.query.order || 'desc'
    },
    fields: req.query.fields ? req.query.fields.split(',') : null
  };

  res.json(response);
});

// Example API calls:
// GET /api/posts?search=node&sortBy=title&order=asc&fields=title,createdAt
// GET /api/posts?startDate=2023-01-01&endDate=2023-12-31&minLength=100
