const express = require('express');
const app = express();
app.use(express.json());

// 1. Add timestamp to all requests
function addTimestamp(req, res, next) {
  req.requestTime = new Date().toISOString();
  next();
}

// 2. Normalize email middleware
function normalizeEmail(req, res, next) {
  if (req.body && req.body.email) {
    req.body.email = req.body.email.toLowerCase().trim();
  }

  // Handle nested objects
  if (req.body && req.body.user && req.body.user.email) {
    req.body.user.email = req.body.user.email.toLowerCase().trim();
  }

  next();
}

// 3. Trim strings middleware
function trimStrings(obj) {
  for (let key in obj) {
    if (typeof obj[key] === 'string') {
      obj[key] = obj[key].trim();
    } else if (typeof obj[key] === 'object' && obj[key] !== null) {
      trimStrings(obj[key]);
    }
  }
  return obj;
}

function trimAllStrings(req, res, next) {
  if (req.body) {
    req.body = trimStrings(req.body);
  }
  if (req.query) {
    req.query = trimStrings(req.query);
  }
  if (req.params) {
    req.params = trimStrings(req.params);
  }
  next();
}

// 4. Convert to proper case
function toProperCase(str) {
  return str.replace(/\w\S*/g, (txt) => {
    return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();
  });
}

function convertNames(req, res, next) {
  if (req.body) {
    if (req.body.firstName) req.body.firstName = toProperCase(req.body.firstName);
    if (req.body.lastName) req.body.lastName = toProperCase(req.body.lastName);
    if (req.body.name) req.body.name = toProperCase(req.body.name);
  }
  next();
}

// 5. Combine all transformations
function transformRequest(req, res, next) {
  // Add timestamp
  req.requestTime = new Date().toISOString();

  // Transform body
  if (req.body) {
    // Normalize emails
    if (req.body.email) req.body.email = req.body.email.toLowerCase().trim();

    // Trim strings
    req.body = trimStrings(req.body);

    // Convert names
    if (req.body.firstName) req.body.firstName = toProperCase(req.body.firstName);
    if (req.body.lastName) req.body.lastName = toProperCase(req.body.lastName);
  }

  next();
}

// Apply middleware
app.use(transformRequest);

// Example route to test transformations
app.post('/api/users', (req, res) => {
  res.json({
    message: 'Request transformed',
    timestamp: req.requestTime,
    receivedData: req.body
  });
});

app.listen(3000, () => {
