const express = require('express');
const app = express();

// In-memory store for rate limiting (use Redis in production)
const requestCounts = new Map();

// Clean up old entries periodically
setInterval(() => {
  const now = Date.now();
  for (const [key, data] of requestCounts.entries()) {
    if (now - data.windowStart > 60000) { // 1 minute
      requestCounts.delete(key);
    }
  }
}, 60000);

// Rate limiter middleware factory
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000, // 1 minute
    max = 100, // max requests per window
    message = 'Too many requests, please try again later',
    keyGenerator = (req) => req.ip,
    skip = (req) => false
  } = options;

  return (req, res, next) => {
    if (skip(req)) {
      return next();
    }

    const key = keyGenerator(req);
    const now = Date.now();

    // Initialize or get existing data for this key
    if (!requestCounts.has(key)) {
      requestCounts.set(key, {
        count: 0,
        windowStart: now
      });
    }

    const data = requestCounts.get(key);

    // Reset window if it has passed
    if (now - data.windowStart > windowMs) {
      data.count = 0;
      data.windowStart = now;
    }

    // Increment count
    data.count++;

    // Calculate remaining requests and reset time
    const remaining = Math.max(0, max - data.count);
    const resetTime = new Date(data.windowStart + windowMs);

    // Set rate limit headers
    res.set('X-RateLimit-Limit', max);
    res.set('X-RateLimit-Remaining', remaining);
    res.set('X-RateLimit-Reset', resetTime.toISOString());

    // Check if limit exceeded
    if (data.count > max) {
      return res.status(429).json({
        error: message,
        retryAfter: Math.ceil((resetTime - now) / 1000)
      });
    }

    next();
  };
}

// Create different rate limiters
const generalLimiter = createRateLimiter({
  windowMs: 60 * 1000, // 1 minute
  max: 100
});

const strictLimiter = createRateLimiter({
  windowMs: 60 * 1000, // 1 minute
  max: 10,
  message: 'Too many requests to this endpoint'
});

const authLimiter = createRateLimiter({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5,
  message: 'Too many login attempts, please try again later',
  keyGenerator: (req) => req.ip + ':auth'
});

// Apply general rate limiter to all routes
app.use(generalLimiter);

// Routes with different rate limits
app.get('/api/data', (req, res) => {
  res.json({ message: 'This is general data' });
});

app.post('/api/sensitive', strictLimiter, (req, res) => {
  res.json({ message: 'This is sensitive data' });
});

app.post('/api/login', authLimiter, (req, res) => {
  // Simulate login
  res.json({ message: 'Login successful' });
});

// Check rate limit status
app.get('/api/rate-limit-status', (req, res) => {
  const key = req.ip;
  const data = requestCounts.get(key);

  if (!data) {
    return res.json({ count: 0, limit: 100, remaining: 100 });
  }

  res.json({
    count: data.count,
    limit: 100,
    remaining: Math.max(0, 100 - data.count),
    resetTime: new Date(data.windowStart + 60000)
  });
});

app.listen(3000, () => {
  console.log('Rate limited server running on port 3000');
});
```

