// server.js
const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

app.use(express.json());

// In-memory 'database' (use JSON files in production)
let posts = [];
let users = [];
let nextId = 1;

// Auth middleware
function auth(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'No token' });
  try {
    req.user = jwt.verify(token, 'secret-key');
    next();
  } catch {
    res.status(401).json({ error: 'Invalid token' });
  }
}

// POST /api/auth/register
app.post('/api/auth/register', (req, res) => {
  const { name, email, password } = req.body;
  if (users.find(u => u.email === email)) {
    return res.status(400).json({ error: 'Email taken' });
  }
  const user = { id: users.length + 1, name, email, password };
  users.push(user);
  const token = jwt.sign({ id: user.id, name, email }, 'secret-key');
  res.json({ token, user: { id: user.id, name, email } });
});

// GET all posts (public)
app.get('/api/posts', (req, res) => {
  res.json(posts.map(p => ({ ...p, author: undefined, authorId: undefined })));
});

// GET single post
app.get('/api/posts/:id', (req, res) => {
  const post = posts.find(p => p.id === parseInt(req.params.id));
  if (!post) return res.status(404).json({ error: 'Post not found' });
  res.json(post);
});

// CREATE post (authenticated)
app.post('/api/posts', auth, (req, res) => {
  const { title, content } = req.body;
  if (!title || !content) {
    return res.status(400).json({ error: 'Title and content required' });
  }
  const post = {
    id: nextId++,
    title,
    content,
    author: req.user.name,
    authorId: req.user.id,
    likes: 0,
    createdAt: new Date().toISOString()
  };
  posts.push(post);
  res.status(201).json(post);
});

// UPDATE post (owner only)
app.put('/api/posts/:id', auth, (req, res) => {
  const post = posts.find(p => p.id === parseInt(req.params.id));
  if (!post) return res.status(404).json({ error: 'Not found' });
  if (post.authorId !== req.user.id) {
    return res.status(403).json({ error: 'Not your post' });
  }
  Object.assign(post, req.body, { updatedAt: new Date().toISOString() });
  res.json(post);
});

// DELETE post (owner only)
app.delete('/api/posts/:id', auth, (req, res) => {
  const index = posts.findIndex(p => p.id === parseInt(req.params.id));
  if (index === -1) return res.status(404).json({ error: 'Not found' });
  if (posts[index].authorId !== req.user.id) {
    return res.status(403).json({ error: 'Not your post' });
  }
  posts.splice(index, 1);
  res.json({ ok: true });
});

// Frontend: Fetch and display posts
async function loadPosts() {
  const spinner = document.getElementById('spinner');
  spinner.style.display = 'block';

  try {
    const response = await fetch('/api/posts');
    if (!response.ok) throw new Error('Failed to load posts');
    const posts = await response.json();

    const feed = document.getElementById('feed');
    feed.innerHTML = posts.map(post => `
      <div class="post-card">
        <h2>${post.title}</h2>
        <p>${post.content.substring(0, 200)}...</p>
        <small>By ${post.author} | ${new Date(post.createdAt).toLocaleDateString()}</small>
        <button onclick="likePost(${post.id})">❤ ${post.likes}</button>
      </div>
    `).join('');
  } catch (error) {
    document.getElementById('feed').innerHTML = 
      '<p class="error">Failed to load posts. Please try again.</p>';
  } finally {
    spinner.style.display = 'none';
  }
}

// Login handler
async function login(email, password) {
  const response = await fetch('/api/auth/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email, password })
  });
  const data = await response.json();
  if (!response.ok) throw new Error(data.error);
  localStorage.setItem('token', data.token);
  showDashboard();
}

